<template>
  <a-layout-footer style="text-align: center">
    海洋生物知识库系统
    <span v-if="user.id"> 欢迎: {{ user.name }}</span>
  </a-layout-footer>
</template>

<script setup>
import { computed, onMounted, onBeforeUnmount } from 'vue'
import store from '@/store'
import { Tool } from '@/utils/tool'
import { notification } from 'ant-design-vue'

const user = computed(() => store.state.user)

let websocket = null
let token = ''

// WebSocket 事件处理函数
const onOpen = () => {
  console.log('WebSocket 连接成功，状态码：', websocket.readyState)
}

const onMessage = (event) => {
  console.log('WebSocket 收到消息：', event.data)
  notification.info({
    message: '收到消息',
    description: event.data,
    duration: 4.5
  })
}

const onError = () => {
  console.log('WebSocket 连接错误，状态码：', websocket.readyState)
}

const onClose = () => {
  console.log('WebSocket 连接关闭，状态码：', websocket.readyState)
}

const initWebSocket = () => {
  if (!websocket) return
  websocket.onopen = onOpen
  websocket.onmessage = onMessage
  websocket.onerror = onError
  websocket.onclose = onClose
}

// 建立 WebSocket 连接
const connectWebSocket = () => {
  if (!('WebSocket' in window)) {
    console.warn('当前浏览器不支持 WebSocket')
    return
  }

  token = Tool.uuid(10) // 生成客户端唯一标识
  const wsUrl = process.env.VUE_APP_WS_SERVER + '/ws/' + token
  websocket = new WebSocket(wsUrl)
  initWebSocket()
}

// 关闭 WebSocket 连接
const closeWebSocket = () => {
  if (websocket && websocket.readyState === WebSocket.OPEN) {
    websocket.close()
  }
}

onMounted(() => {
  connectWebSocket()
})

onBeforeUnmount(() => {
  closeWebSocket()
})
</script>

<style scoped>
/* 可自定义样式 */
</style>
