/**
 * 工具类 - 提供常用工具方法
 */
export class Tool {
  /**
   * 空校验 null或""都返回true
   */
  static isEmpty (obj) {
    if (typeof obj === 'string') {
      return !obj || obj.replace(/\s+/g, '') === ''
    } else {
      return (!obj || JSON.stringify(obj) === '{}' || obj.length === 0)
    }
  }

  /**
   * 非空校验
   */
  static isNotEmpty (obj) {
    return !this.isEmpty(obj)
  }

  /**
   * 对象复制
   * @param {object} obj - 要复制的对象
   */
  static copy (obj) {
    if (Tool.isNotEmpty(obj)) {
      return JSON.parse(JSON.stringify(obj))
    }
  }

  /**
   * 使用递归将数组转为树形结构
   * 父ID属性为parent
   * @param {Array} array - 数据数组
   * @param {number} parentId - 父级ID
   * @returns {Array} 树形结构数组
   */
  static array2Tree (array, parentId) {
    if (Tool.isEmpty(array)) {
      return []
    }
    const result = []
    for (let i = 0; i < array.length; i++) {
      const c = array[i]
      // console.log(String(c.parent), String(parentId));
      if (String(c.parent) === String(parentId)) {
        result.push(c)

        // 递归查看当前节点对应的子节点
        const children = Tool.array2Tree(array, c.id)
        if (Tool.isNotEmpty(children)) {
          c.children = children
        }
      }
    }
    return result
  }

  /**
   * 随机生成[len]长度的[radix]进制数
   * @param {number} len - 生成字符串的长度
   * @param {number} radix - 进制数，默认62
   * @returns {string} 随机字符串
   */
  static uuid (len, radix = 62) {
    const chars = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz'.split('')
    const uuid = []
    radix = radix || chars.length

    for (let i = 0; i < len; i++) {
      uuid[i] = chars[0 | Math.random() * radix]
    }

    return uuid.join('')
  }
}
