<template>
  <div style="padding: 20px; max-width: 800px; margin: 0 auto;">
    <!-- 欢迎词 -->
    <div style="text-align: center; margin-bottom: 20px;">
      <h1 style="font-size: 24px; color: #1890ff;">欢迎来到海洋生物知识库</h1>
      <p style="font-size: 14px; color: #666; margin-top: 8px;">请从左侧菜单选择分类查看海洋生物</p>
    </div>

    <!-- 数据卡片：内部分三行，紧凑排列 -->
    <a-row>
      <a-col :span="24">
        <a-card>
          <a-row>
            <a-col :span="8">
              <a-statistic title="总阅读量" :value="statistic.viewCount">
                <template #suffix>
                  <UserOutlined />
                </template>
              </a-statistic>
            </a-col>
            <a-col :span="8">
              <a-statistic title="总点赞量" :value="statistic.voteCount">
                <template #suffix>
                  <like-outlined />
                </template>
              </a-statistic>
            </a-col>
            <a-col :span="8">
              <a-statistic title="点赞率" :value="statistic.voteCount / statistic.viewCount * 100"
                           :precision="2"
                           suffix="%"
                           :value-style="{ color: '#cf1322' }">
                <template #suffix>
                  <like-outlined />
                </template>
              </a-statistic>
            </a-col>
          </a-row>
        </a-card>
      </a-col>
    </a-row>
    <br>
    <a-row :gutter="16">
      <a-col :span="12">
        <a-card>
          <a-row>
            <a-col :span="12">
              <a-statistic title="今日阅读" :value="statistic.todayViewCount" style="margin-right: 50px">
                <template #suffix>
                  <UserOutlined />
                </template>
              </a-statistic>
            </a-col>
            <a-col :span="12">
              <a-statistic title="今日点赞" :value="statistic.todayVoteCount">
                <template #suffix>
                  <like-outlined />
                </template>
              </a-statistic>
            </a-col>
          </a-row>
        </a-card>
      </a-col>
      <a-col :span="12">
        <a-card>
          <a-row>
            <a-col :span="12">
              <a-statistic
                  title="预计今日阅读"
                  :value="statistic.todayViewIncrease"
                  :value-style="{ color: '#0000ff' }"
              >
                <template #suffix>
                  <UserOutlined />
                </template>
              </a-statistic>
            </a-col>
            <a-col :span="12">
              <a-statistic
                  title="预计今日阅读增长"
                  :value="statistic.todayViewIncreaseRateAbs"
                  :precision="2"
                  suffix="%"
                  class="demo-class"
                  :value-style="statistic.todayViewIncreaseRate < 0 ? { color: '#3f8600' } : { color: '#cf1322' }"
              >
                <template #prefix>
                  <arrow-down-outlined v-if="statistic.todayViewIncreaseRate < 0"/>
                  <arrow-up-outlined v-if="statistic.todayViewIncreaseRate >= 0"/>
                </template>
              </a-statistic>
            </a-col>
          </a-row>
        </a-card>
      </a-col>
    </a-row>
    <br>

    <!-- 30天趋势图（高度缩小） -->
    <a-card :bordered="true">
      <div id="main" style="width: 100%; height: 200px;"></div>
    </a-card>
  </div>
</template>

<script setup>
import { ref, onMounted } from 'vue'
import axios from 'axios'
import { message } from 'ant-design-vue'
import * as echarts from 'echarts'

// ---------- 统计数据 ----------
const statistic = ref({
  viewCount: 0,
  voteCount: 0,
  todayViewCount: 0,
  todayVoteCount: 0,
  todayViewIncrease: 0,
  todayViewIncreaseRate: 0,
  todayViewIncreaseRateAbs: 0
})

// ---------- 获取今日统计 ----------
const getStatistic = () => {
  axios.get('/ebookSnapshot/getStatistic')
    .then((response) => {
      const data = response.data
      if (data.success) {
        const list = data.content || []
        const yesterday = list[0] || {}
        const today = list.length > 1 ? (list[1] || {}) : (list[0] || {})

        statistic.value.viewCount = today.viewCount || 0
        statistic.value.voteCount = today.voteCount || 0
        statistic.value.todayViewCount = today.viewIncrease || 0
        statistic.value.todayVoteCount = today.voteIncrease || 0

        const now = new Date()
        const nowRate = (now.getHours() * 60 + now.getMinutes()) / (60 * 24)
        const predicted = nowRate > 0 ? Math.round(today.viewIncrease / nowRate) : 0
        statistic.value.todayViewIncrease = predicted

        const yesterdayView = yesterday.viewIncrease || 0
        if (yesterdayView === 0) {
          statistic.value.todayViewIncreaseRate = 100
        } else {
          const rate = (predicted - yesterdayView) / yesterdayView * 100
          statistic.value.todayViewIncreaseRate = rate
        }
        statistic.value.todayViewIncreaseRateAbs = Math.abs(statistic.value.todayViewIncreaseRate)
      } else {
        message.error(data.message || '获取统计数据失败')
      }
    })
    .catch((err) => {
      console.error('获取统计数据失败:', err)
      message.error('获取统计数据失败，请稍后重试')
    })
}

// ---------- 30天趋势图 ----------
const init30DayEcharts = (list) => {
  // 清空并重新创建容器，解决页面切换后图表不显示的问题
  const mainDom = document.getElementById('main-col')
  if (mainDom) {
    mainDom.innerHTML = '<div id="main" style="width: 100%;height:300px;"></div>'
  }

  const myChart = echarts.init(document.getElementById('main'))

  const xAxis = []
  const seriesView = []
  const seriesVote = []

  for (let i = 0; i < list.length; i++) {
    const record = list[i]
    xAxis.push(record.date)
    seriesView.push(record.viewIncrease)
    seriesVote.push(record.voteIncrease)
  }

  const option = {
    title: {
      text: '30天趋势图'
    },
    tooltip: {
      trigger: 'axis'
    },
    legend: {
      data: ['总阅读量', '总点赞量']
    },
    grid: {
      left: '1%',
      right: '3%',
      bottom: '3%',
      containLabel: true
    },
    toolbox: {
      feature: {
        saveAsImage: {}
      }
    },
    xAxis: {
      type: 'category',
      boundaryGap: false,
      data: xAxis
    },
    yAxis: {
      type: 'value'
    },
    series: [
      {
        name: '总阅读量',
        type: 'line',
        data: seriesView,
        smooth: true
      },
      {
        name: '总点赞量',
        type: 'line',
        data: seriesVote,
        smooth: true
      }
    ]
  }

  myChart.setOption(option)
  window.addEventListener('resize', () => myChart.resize())
}

// ---------- 获取30天统计 ----------
const get30DayStatistic = () => {
  axios.get('/ebookSnapshot/get30Statistic')
    .then((response) => {
      const data = response.data
      if (data.success) {
        const statisticList = data.content || []
        init30DayEcharts(statisticList)
      } else {
        message.error(data.message || '获取30天趋势数据失败')
      }
    })
    .catch((err) => {
      console.error('获取30天趋势数据失败:', err)
      message.error('获取30天趋势数据失败，请稍后重试')
    })
}

// ---------- 生命周期 ----------
onMounted(() => {
  getStatistic()
  get30DayStatistic()
})
</script>

<style scoped>
/* 可自定义样式 */
</style>
