import { createRouter, createWebHashHistory } from 'vue-router'
import HomeView from '../views/HomeView.vue'
import store from '@/store'
import { message } from 'ant-design-vue'
import { Tool } from '@/utils/tool' // 使用已添加的 Tool 工具类

const routes = [
  {
    path: '/',
    name: 'home',
    component: HomeView
  },
  {
    path: '/about',
    name: 'about',
    component: () => import(/* webpackChunkName: "about" */ '../views/AboutView.vue')
  },
  {
    path: '/admin/ebook',
    name: 'adminEbook',
    component: () => import('../views/admin/admin-ebook.vue'),
    meta: { loginRequire: true, requireAdmin: true }
  },
  {
    path: '/admin/category',
    name: 'adminCategory',
    component: () => import('../views/admin/admin-category.vue'),
    meta: { loginRequire: true, requireAdmin: true }
  },
  {
    path: '/admin/doc',
    name: 'AdminDoc',
    component: () => import('../views/admin/admin-doc.vue'),
    meta: { loginRequire: true, requireAdmin: true }
  },
  {
    path: '/doc',
    name: 'Doc',
    component: () => import('../views/DocView.vue'),
    meta: { loginRequire: true } // 根据业务需求，可改为 false 或删除该行
  },
  {
    path: '/admin/user',
    name: 'AdminUser',
    component: () => import('../views/admin/admin-user.vue'),
    meta: { loginRequire: true, requireAdmin: true }
  }
]

const router = createRouter({
  history: createWebHashHistory(),
  routes
})

// ---------- 路由登录拦截守卫 ----------
router.beforeEach((to, from, next) => {
  if (to.matched.some(record => record.meta.loginRequire)) {
    const loginUser = store.state.user
    if (Tool.isEmpty(loginUser) || !loginUser.token) {
      message.error('请先登录！')
      next('/')
    } else {
      next()
    }
  } else if (to.matched.some(record => record.meta.requireAdmin)) { // 管理员专用页面
    const loginUser = store.state.user
    if (Tool.isEmpty(loginUser) || loginUser.role !== 'admin') {
      message.error('无权限访问')
      next('/')
    } else {
      next()
    }
  } else {
    next()
  }
})

export default router
