<template>
  <a-layout style="min-height: 100vh; background: #fff;">
    <!-- 左侧分类菜单 -->
    <a-layout-sider width="200" style="background: #fff; border-right: 1px solid #f0f0f0;">
      <a-menu
        mode="inline"
        style="height: 100%; border-right: 0;"
        :selected-keys="selectedKeys"
        :default-open-keys="defaultOpenKeys"
        @click="handleMenuClick"
      >
        <a-menu-item key="welcome">
          <SmileOutlined />           <!-- ← MailOutlined → SmileOutlined -->
          <span>欢迎</span>
        </a-menu-item>
        <a-sub-menu v-for="item in level1" :key="item.id">
          <template #title>
            <span><BookOutlined />{{ item.name }}</span>    <!-- ← UserOutlined → BookOutlined -->
          </template>
          <a-menu-item v-for="child in item.children" :key="child.id">
            <StarOutlined /><span>{{ child.name }}</span>   <!-- ← MailOutlined → StarOutlined -->
          </a-menu-item>
        </a-sub-menu>
      </a-menu>
    </a-layout-sider>

    <!-- 右侧内容 -->
    <a-layout-content style="padding: 20px;">
      <!-- 面包屑导航 -->
      <a-breadcrumb style="margin-bottom: 16px;">
        <a-breadcrumb-item>
          <router-link to="/">首页</router-link>
        </a-breadcrumb-item>
        <a-breadcrumb-item v-if="!isShowWelcome && breadcrumbPath.length > 0">
          {{ breadcrumbPath[0] }}
        </a-breadcrumb-item>
        <a-breadcrumb-item v-if="!isShowWelcome && breadcrumbPath.length > 1">
          {{ breadcrumbPath[1] }}
        </a-breadcrumb-item>
      </a-breadcrumb>

      <!-- 欢迎页（含数据统计） -->
      <the-welcome v-show="isShowWelcome" />

      <!-- 电子书列表 -->
      <div v-show="!isShowWelcome">
        <h2>{{ currentCategoryName }}</h2>
        <a-list
          v-if="Array.isArray(dataSource)"
          item-layout="vertical"
          size="large"
          :grid="{ gutter: 20, column: 3 }"
          :pagination="pagination"
          :data-source="dataSource"
        >
          <template #renderItem="{ item }">
            <a-list-item key="item.name">
              <!-- 动态动作图标：文档数、阅读数、点赞数 -->
              <template #actions>
                <span>
                  <FileOutlined style="margin-right: 8px;" />
                  {{ item.docCount }}
                </span>
                <span>
                  <EyeOutlined style="margin-right: 8px;" />
                  {{ item.viewCount }}
                </span>
                <span>
                  <LikeOutlined style="margin-right: 8px;" />
                  {{ item.voteCount }}
                </span>
              </template>

              <a-list-item-meta :description="item.description">
                <template #title>
                  <router-link :to="'/doc?ebookId=' + item.id">
                    {{ item.name }}
                  </router-link>
                </template>
                <template #avatar>
                  <a-avatar v-if="item.cover" :src="item.cover" style="width: 80px; height: 80px;" />
                  <a-avatar v-else style="width: 80px; height: 80px; line-height: 80px; text-align: center; background: #e8f4fd; color: #1890ff; font-size: 24px; display: inline-block;">
                    {{ item.name ? item.name.slice(0, 1) : '?' }}
                  </a-avatar>
                </template>
              </a-list-item-meta>
            </a-list-item>
          </template>
        </a-list>
      </div>
    </a-layout-content>
  </a-layout>
</template>

<script setup>
import { ref, onMounted, computed } from 'vue'
import axios from 'axios'
import TheWelcome from '@/components/the-welcome'
import { StarOutlined, LikeOutlined, SmileOutlined, BookOutlined, FileOutlined, EyeOutlined } from '@ant-design/icons-vue'
import { message } from 'ant-design-vue'

// const BASE_URL = axios.defaults.baseURL

// ---------- 分类数据 ----------
const level1 = ref([])
const selectedKeys = ref(['welcome'])
const defaultOpenKeys = ref([])
const isShowWelcome = ref(true)
const currentCategoryId2 = ref(0)
const currentCategoryName = ref('')
const breadcrumbPath = ref([])

// 树形结构构建
const buildTree = (list, parentId = 0) => {
  const pid = String(parentId)
  return list
    .filter(item => String(item.parent) === pid)
    .map(item => ({
      ...item,
      children: buildTree(list, item.id)
    }))
}

// 根据 ID 查找分类名称
const findCategoryName = (id, list) => {
  for (const item of list) {
    if (String(item.id) === String(id)) {
      return item.name
    }
    if (item.children) {
      const name = findCategoryName(id, item.children)
      if (name) return name
    }
  }
  return ''
}

// 查询分类
const handleQueryCategory = () => {
  axios.get('/category/all')
    .then((resp) => {
      const data = resp.data
      if (data.success) {
        const rawList = data.content || []
        level1.value = buildTree(rawList, 0)
        defaultOpenKeys.value = level1.value.map(item => String(item.id))
      } else {
        message.error(data.message || '加载分类失败')
      }
    })
    .catch((err) => {
      console.error('分类加载失败:', err)
      message.error('分类加载失败，请检查网络')
    })
}

// 菜单点击事件
const handleMenuClick = ({ key, keyPath }) => {
  selectedKeys.value = [key]
  if (key === 'welcome') {
    isShowWelcome.value = true
    breadcrumbPath.value = []
  } else {
    isShowWelcome.value = false
    currentCategoryId2.value = key

    // 构建面包屑
    const path = []
    const reversed = [...keyPath].reverse()
    for (const id of reversed) {
      const name = findCategoryName(id, level1.value)
      if (name) path.push(name)
    }
    breadcrumbPath.value = path
    currentCategoryName.value = path[path.length - 1] || ''

    queryBooks(1, pagination.value.pageSize, key)
  }
}

// ---------- 书籍列表 ----------
const ebooks = ref([])
const dataSource = computed(() => {
  return Array.isArray(ebooks.value) ? ebooks.value : []
})

const pagination = ref({
  current: 1,
  pageSize: 3,
  total: 0,
  showSizeChanger: true,
  pageSizeOptions: ['3', '5', '10', '20'],
  showTotal: total => `共 ${total} 条`,
  onChange: (page, pageSize) => {
    queryBooks(page, pageSize, currentCategoryId2.value)
  },
  onShowSizeChange: (current, size) => {
    pagination.value.pageSize = size
    pagination.value.current = 1
    queryBooks(1, size, currentCategoryId2.value)
  }
})

const queryBooks = (page = 1, size = 3, categoryId2 = 0) => {
  const params = { page, size }
  if (categoryId2) {
    params.categoryId2 = categoryId2
  }
  axios.get('/ebook/list', { params })
    .then(resp => {
      const data = resp.data
      const content = data.content || { list: [], total: 0 }
      const list = content.list || []
      ebooks.value = list.map(item => ({
        ...item,
        cover: item.cover || ''
      }))
      pagination.value.total = content.total || 0
      pagination.value.current = page
    })
    .catch(err => {
      console.error('请求失败:', err)
      ebooks.value = []
      pagination.value.total = 0
    })
}

onMounted(() => {
  handleQueryCategory()
})
</script>

<style scoped>
.welcome {
  text-align: center;
  padding: 80px 0;
}
.welcome h1 {
  font-size: 28px;
  color: #1890ff;
}
.welcome p {
  font-size: 16px;
  color: #666;
  margin-top: 16px;
}
</style>
