<template>
  <a-layout-header class="header">
    <!-- Logo 文字 -->
    <div class="logo">海洋生物知识库</div>

    <a-menu
      theme="dark"
      mode="horizontal"
      :style="{ lineHeight: '64px', display: 'block' }"
      v-model:selectedKeys="selectedKeys"
    >
      <!-- 菜单项全部左浮动 -->
      <a-menu-item key="/" style="float: left;">
        <router-link to="/">首页</router-link>
      </a-menu-item>
      <!-- 后台管理菜单：仅登录后可见 -->
      <a-menu-item key="/admin/ebook" style="float: left;" v-if="loginUser.role === 'admin'">
        <router-link to="/admin/ebook">海洋生物种类管理</router-link>
      </a-menu-item>
      <a-menu-item key="/admin/category" style="float: left;" v-if="loginUser.role === 'admin'">
        <router-link to="/admin/category">海洋生物分类管理</router-link>
      </a-menu-item>
      <a-menu-item key="/admin/user" style="float: left;" v-if="loginUser.role === 'admin'">
        <router-link to="/admin/user">用户管理</router-link>
      </a-menu-item>
      <a-menu-item key="/about" style="float: left;">
        <router-link to="/about">关于我们</router-link>
      </a-menu-item>

      <!-- 右侧用户信息与登录（右浮动） -->
      <a-menu-item key="login" style="float: right;">
        <a-popconfirm
          v-if="loginUser.id"
          title="确认退出登录?"
          ok-text="是"
          cancel-text="否"
          @confirm="logout"
        >
          <a style="cursor: pointer;">退出登录</a>
        </a-popconfirm>
        <a v-else @click="showLoginModal">登录</a>
      </a-menu-item>
      <!-- 用户信息放在后面，显示在最右侧 -->
      <a-menu-item key="user" style="float: right;">
        <span v-if="loginUser.id">您好：{{ loginUser.name }}</span>
      </a-menu-item>
    </a-menu>

    <!-- 登录弹窗 -->
    <a-modal
      title="登录"
      v-model:open="loginModalVisible"
      :confirm-loading="loginModalLoading"
      @ok="handleLogin"
    >
      <a-form :model="loginForm" :label-col="{ span: 6 }" :wrapper-col="{ span: 18 }">
        <a-form-item label="登录名">
          <a-input v-model:value="loginForm.loginName" placeholder="请输入登录名" />
        </a-form-item>
        <a-form-item label="密码">
          <a-input v-model:value="loginForm.password" type="password" placeholder="请输入密码" />
        </a-form-item>
      </a-form>
    </a-modal>
  </a-layout-header>
</template>

<script setup>
/* global hexMd5, KEY */
import { ref, onMounted, watch, computed } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { message } from 'ant-design-vue'
import axios from 'axios'
import store from '@/store'

const route = useRoute()
const router = useRouter()

// ---------- 菜单高亮 ----------
const selectedKeys = ref(['/'])

const updateMenu = () => {
  const path = route.path
  if (path === '/admin/ebook' || path === '/admin/category' || path === '/admin/user') {
    selectedKeys.value = ['/admin/ebook']
  } else {
    selectedKeys.value = ['/']
  }
}

onMounted(updateMenu)
watch(() => route.path, updateMenu)

// ---------- 用户状态（从 Vuex 获取） ----------
const loginUser = computed(() => store.state.user)

// ---------- 登录相关 ----------
const loginModalVisible = ref(false)
const loginModalLoading = ref(false)
const loginForm = ref({
  loginName: '',
  password: ''
})

const showLoginModal = () => {
  loginModalVisible.value = true
  loginForm.value = { loginName: '', password: '' }
}

const handleLogin = () => {
  if (!loginForm.value.loginName || !loginForm.value.password) {
    message.warning('请输入登录名和密码')
    return
  }
  loginModalLoading.value = true
  const encryptedPassword = hexMd5(loginForm.value.password + KEY)
  axios.post('/user/login', {
    loginName: loginForm.value.loginName,
    password: encryptedPassword
  })
    .then((resp) => {
      loginModalLoading.value = false
      const data = resp.data
      if (data.success) {
        loginModalVisible.value = false
        store.commit('setUser', data.content)
        message.success('登录成功！')
        router.push('/')
      } else {
        message.error(data.message || '登录失败')
      }
    })
    .catch(() => {
      loginModalLoading.value = false
      message.error('登录失败，请重试')
    })
}

// ---------- 退出登录 ----------
const logout = () => {
  console.log('退出登录开始')
  // 先清空本地状态（无论后端是否成功）
  store.commit('setUser', {})

  // 再尝试通知后端清除 token（可选，失败不影响退出）
  const token = loginUser.value.token
  if (token) {
    axios.get(`/user/logout/${token}`)
      .then((resp) => {
        if (resp.data.success) {
          console.log('后端 token 已清除')
        }
      })
      .catch(() => {
        console.log('后端 token 清除失败（可能 Redis 未启动），不影响退出')
      })
  }

  message.success('退出登录成功！')
  router.push('/')
}
</script>

<style scoped>
.logo {
  float: left;
  width: 150px;
  height: 64px;          /* 与 header 高度一致，垂直居中 */
  line-height: 64px;     /* 文字垂直居中 */
  color: #fff;
  font-size: 18px;
  font-weight: bold;
  margin-right: 24px;
  /* 去掉背景色，保留纯文字 */
  background: transparent;
}

/* 清除浮动，确保父容器高度正确 */
.ant-menu {
  overflow: hidden;
}
</style>
